import React from 'react';
import styled from "styled-components";

const Background = styled.div`
  height: 100vh;
  background-position: center;
  background-color: #151719;
`;

const Appname = styled.div`
  margin: auto;
  width: 50%;
  border: 3px solid green;
  padding: 10px;
    `;


// Testing background
export const Home = ()=> {
    return (
        <Background>
            <Appname>
                Climate Watch
            </Appname>
        </Background>

    )
}
